sql:
SELECT COUNT(*)
FROM gift_basket_redemptions
WHERE status = 'completed';

SELECT COUNT(gift_basket_id) AS active_gift_baskets
FROM gift_baskets
WHERE status = 'active';

SELECT item_name, quantity
FROM gift_basket_contents
WHERE gift_basket_id = 1;

SELECT AVG(gb.price) AS average_price
FROM gift_baskets gb
WHERE gb.status = 'active' AND gb.stock_quantity > 10;

SELECT COUNT(DISTINCT gift_basket_id) AS total_distinct_gift_baskets_redeemed
FROM gift_basket_redemptions
WHERE status = 'completed';

SELECT COUNT(*) AS total_completed_redemptions
FROM gift_basket_redemptions
WHERE status = 'completed';

SELECT DISTINCT gb.name
FROM gift_baskets gb
JOIN gift_basket_redemptions gbr ON gb.gift_basket_id = gbr.gift_basket_id;

external_knowledge:
- "availability details" refers to both the stock quantity and the price of the gift baskets;
- "most popular" here implies a higher stock quantity, as it suggests more are available, indicating higher popularity or demand;
- "active" means the gift basket is currently available for purchase.

- 'generous participants' refers to users who have received rewards;
- 'total value of gifts' corresponds to the sum of the in-game values or points of the items in the rewards;
- 'online handles' are the usernames of the users;
- 'contact details' refer to the email addresses of the users.
